  1→//! Stage 1 (Observe): Execute a function with pre-generated inputs and collect
  2→//! execution traces. Pure observation — no Z3 or constraint solving.
  3→//!
  4→//! The observe module provides a composable building block: given a function and
  5→//! a list of inputs, it executes each input via the language frontend and returns
  6→//! structured trace data (branch coverage, line coverage, side effects, discovery
  7→//! attribution). Callers are responsible for generating inputs (random, boundary,
  8→//! user-provided) before calling into this module.
  9→
 10→use std::collections::HashSet;
 11→use std::time::{Duration, Instant};
 12→
 13→use serde::{Deserialize, Serialize};
 14→
 15→use crate::protocol::SetupLevel;
 16→use crate::protocol::SetupContextStack;
 17→use crate::coverage_metrics::DiscoveryMethod;
 18→use crate::explorer::{
 19→    classify_error_intent, frontend_supports, path_hash, send_setup, send_teardown,
 20→    ExecutionSummary, ExploreError, LoopBuckets, ObservationOutput,
 21→};
 22→use crate::frontend::{Frontend, FrontendError};
 23→use crate::orchestrator::FrontendCapabilities;
 24→use crate::protocol::{
 25→    Command as ProtoCommand, ExecuteResult, FunctionAnalysis, MockConfig, ResponseResult,
 26→};
 27→
 28→/// Errors that can occur during observation.
 29→#[derive(Debug, thiserror::Error)]
 30→pub enum ObserveError {
 31→    #[error("frontend error: {0}")]
 32→    Frontend(#[from] FrontendError),
 33→    #[error("unexpected response from frontend: {0}")]
 34→    UnexpectedResponse(String),
 35→    #[error("instrumentation failed: {0}")]
 36→    InstrumentationFailed(String),
 37→}
 38→
 39→impl From<ExploreError> for ObserveError {
 40→    fn from(e: ExploreError) -> Self {
 41→        match e {
 42→            ExploreError::Frontend(fe) => Self::Frontend(fe),
 43→            ExploreError::UnexpectedResponse(msg) => Self::UnexpectedResponse(msg),
 44→        }
 45→    }
 46→}
 47→
 48→/// Configuration for the observe stage. Contains only execution-related settings;
 49→/// input generation is the caller's responsibility.
 50→#[derive(Debug, Clone)]
 51→pub struct ObserveConfig {
 52→    /// Path to the source file (needed for instrumentation).
 53→    pub file: String,
 54→    /// Mock configurations to pass to Execute commands.
 55→    pub mocks: Vec<MockConfig>,
 56→    /// Path to the setup file, if configured.
 57→    pub setup_file: Option<String>,
 58→    /// When to run setup relative to executions.
 59→    pub setup_level: SetupLevel,
 60→    /// Frontend capabilities (used to gate setup/teardown commands).
 61→    pub capabilities: FrontendCapabilities,
 62→    /// Detected project root directory.
 63→    pub project_root: Option<String>,
 64→    /// Iteration count bucket boundaries for loop-aware path hashing.
 65→    pub loop_buckets: LoopBuckets,
 66→    /// Wall-clock timeout for the entire observation phase.
 67→    pub timeout: Option<Duration>,
 68→    /// Skip the Instrument command (caller already instrumented).
 69→    pub skip_instrument: bool,
 70→}
 71→
 72→impl From<&crate::explorer::ExploreConfig> for ObserveConfig {
 73→    fn from(ec: &crate::explorer::ExploreConfig) -> Self {
 74→        Self {
 75→            file: ec.file.clone(),
 76→            mocks: ec.mocks.clone(),
 77→            setup_file: ec.setup_file.clone(),
 78→            setup_level: ec.setup_level,
 79→            capabilities: ec.capabilities.clone(),
 80→            project_root: ec.project_root.clone(),
 81→            loop_buckets: ec.loop_buckets.clone(),
 82→            timeout: ec.timeout_explore,
 83→            skip_instrument: false,
 84→        }
 85→    }
 86→}
