423→#[cfg(test)]
424→mod tests {
425→    use super::*;
426→    use crate::execution_record::{BranchDecision, SymConstraint};
427→    use crate::protocol::{ExecuteResult, PerformanceMetrics};
428→
429→    /// Build a minimal ExecuteResult with specified branch decisions and lines.
430→    fn make_exec_result(
431→        branch_ids: &[(u32, bool)],
432→        lines: &[u32],
433→    ) -> ExecuteResult {
434→        ExecuteResult {
435→            return_value: Some(serde_json::json!(42)),
436→            thrown_error: None,
437→            branch_path: branch_ids
438→                .iter()
439→                .map(|&(id, taken)| BranchDecision {
440→                    branch_id: id,
441→                    line: id * 10,
442→                    taken,
443→                    constraint: SymConstraint::Unknown {
444→                        hint: String::new(),
445→                    },
446→                })
447→                .collect(),
448→            lines_executed: lines.to_vec(),
449→            calls_to_external: vec![],
450→            path_constraints: vec![],
451→            scope_events: vec![],
452→            side_effects: vec![],
453→            performance: PerformanceMetrics {
454→                wall_time_ms: 1.0,
455→                cpu_time_us: 1000,
456→                heap_used_bytes: 0,
457→                heap_allocated_bytes: 0,
458→            },
459→            capture_truncation: None,
460→        }
461→    }
462→
463→    #[test]
464→    fn batch_observation_path_dedup() {
465→        // Two identical exec results should yield 1 unique path.
466→        let r1 = make_exec_result(&[(1, true), (2, false)], &[10, 20]);
467→        let r2 = make_exec_result(&[(1, true), (2, false)], &[10, 20]);
468→
469→        let buckets = LoopBuckets::none();
470→        let h1 = path_hash(&r1, &buckets);
471→        let h2 = path_hash(&r2, &buckets);
472→
473→        assert_eq!(h1, h2, "identical branch paths should produce same hash");
474→
475→        // Different branch decisions should produce different hashes.
476→        let r3 = make_exec_result(&[(1, true), (2, true)], &[10, 20, 30]);
477→        let h3 = path_hash(&r3, &buckets);
478→        assert_ne!(h1, h3, "different branch paths should produce different hashes");
479→    }
480→
481→    #[test]
482→    fn batch_observation_discovery_uniqueness() {
483→        // Each branch_id should appear at most once in discoveries.
484→        let mut seen_branch_ids: HashSet<u32> = HashSet::new();
485→        let mut discoveries: Vec<(u32, DiscoveryMethod)> = Vec::new();
486→
487→        // Simulate two executions hitting overlapping branches.
488→        let branches_1 = vec![1u32, 2, 3];
489→        let branches_2 = vec![2u32, 3, 4];
490→
491→        for branch_id in branches_1 {
492→            if seen_branch_ids.insert(branch_id) {
493→                discoveries.push((branch_id, DiscoveryMethod::Random));
494→            }
495→        }
496→        for branch_id in branches_2 {
497→            if seen_branch_ids.insert(branch_id) {
498→                discoveries.push((branch_id, DiscoveryMethod::Random));
499→            }
500→        }
501→
502→        // Branch IDs 1, 2, 3, 4 — each discovered exactly once.
503→        assert_eq!(discoveries.len(), 4);
504→        let ids: HashSet<u32> = discoveries.iter().map(|(id, _)| *id).collect();
505→        assert_eq!(ids, HashSet::from([1, 2, 3, 4]));
506→    }
507→
508→    #[test]
509→    fn batch_observation_lines_covered_union() {
510→        // Lines covered should be the union across all executions.
511→        let mut all_lines: HashSet<u32> = HashSet::new();
512→
513→        let r1 = make_exec_result(&[(1, true)], &[10, 20, 30]);
514→        let r2 = make_exec_result(&[(1, false)], &[10, 40, 50]);
515→
516→        for &line in &r1.lines_executed {
517→            all_lines.insert(line);
518→        }
519→        for &line in &r2.lines_executed {
520→            all_lines.insert(line);
521→        }
522→
523→        assert_eq!(all_lines, HashSet::from([10, 20, 30, 40, 50]));
524→    }
